import threading
import random

class BankAccount:
    def __init__(self, name, balance):
        self.name = name
        self.balance = balance
        self.lock = threading.Lock()

    def deposit(self, amount):
        print(f"{self.name} deposited ${amount}.")
        with self.lock:
            self.balance += amount

    def withdraw(self, amount):
        print(f"{self.name} withdrew ${amount}.")
        with self.lock:
            if self.balance >= amount:
                self.balance -= amount
            else:
                raise ValueError(f"{self.name} has insufficient funds.")

    def transfer_funds(self, amount, other_account):
        with self.lock:
            if self.balance >= amount:
                self.withdraw(amount)
                other_account.deposit(amount)
                print(f"${amount} transferred from {self.name} to {other_account.name}.")
            else:
                raise ValueError(f"{self.name} has insufficient funds for transfer.")

class ThreadedBank:
    def __init__(self):
        self.account1 = BankAccount("Account 1", 1000)
        self.account2 = BankAccount("Account 2", 500)
        self.stop_event = threading.Event()

    def run_account1(self):
        while not self.stop_event.is_set():
            action = random.choice(["deposit", "withdraw"])
            amount = random.randint(10, 100)

            if action == "deposit":
